import json
import asyncio
import logging
import urllib.parse
from urllib.error import URLError, HTTPError
from urllib.request import Request, urlopen

logger = logging.getLogger()
logger.setLevel(logging.INFO)

async def fetch_url_data(url):
    """
    Asynchronously fetches data from a given URL.
    """
    try:
        logger.info(f"Fetching data from: {url}")
        req = Request(url)
        with urlopen(req) as response:
            data = response.read().decode('utf-8')
            logger.info(f"Successfully fetched data from {url}, length: {len(data)}")
            try:
                # Attempt to parse as JSON if possible
                return json.loads(data)
            except json.JSONDecodeError:
                # Return as raw string if not JSON
                return data
    except HTTPError as e:
        logger.error(f"HTTP Error fetching {url}: {e.code} - {e.reason}")
    except URLError as e:
        logger.error(f"URL Error fetching {url}: {e.reason}")
    except Exception as e:
        logger.error(f"Unexpected error fetching {url}: {e}")
    return None

async def lambda_handler(event, context):
    """
    Lambda@Edge viewer request handler that fetches data from URLs
    specified in X-Enrich-URL headers.
    """
    request = event['Records'][0]['cf']['request']
    headers = request['headers']

    enrich_urls = []
    if 'x-enrich-url' in headers:
        for header_value in headers['x-enrich-url']:
            # The value could be a comma-separated list of URLs
            urls_in_header = header_value['value'].split(',')
            for url in urls_in_header:
                clean_url = url.strip()
                if clean_url:
                    enrich_urls.append(clean_url)
    
    enriched_data = {}
    if enrich_urls:
        logger.info(f"Found {len(enrich_urls)} enrichment URLs: {enrich_urls}")
        
        # Use asyncio.gather to fetch all URLs concurrently
        tasks = [fetch_url_data(url) for url in enrich_urls]
        results = await asyncio.gather(*tasks)

        for i, data in enumerate(results):
            if data is not None:
                # Use a simple key for each piece of enriched data, e.g., "enrich_data_0", "enrich_data_1"
                # Or use a URL-derived key if desired, but this could get long.
                # For simplicity, using index for now.
                key = f"enrich_data_{i}"
                enriched_data[key] = data
            else:
                logger.warning(f"No data returned for URL: {enrich_urls[i]}")

    # Add enriched data to a custom header to pass to the origin
    # Ensure the data is JSON-serializable and URL-encoded.
    # CloudFront header values must be strings.
    if enriched_data:
        try:
            enriched_data_str = json.dumps(enriched_data, separators=(',', ':'))
            # CloudFront headers cannot contain certain characters, so URL-encode the value.
            # Make sure to decode this on the origin.
            encoded_enriched_data = urllib.parse.quote(enriched_data_str)
            logger.info(f"Adding X-Enriched-Context header with length: {len(encoded_enriched_data)}")
            
            # Note: CloudFront imposes a total header size limit (~10KB-40KB for custom headers),
            # so large enrichment data might need a different strategy (e.g., S3 object pointer).
            request['headers']['x-enriched-context'] = [{'key': 'X-Enriched-Context', 'value': encoded_enriched_data}]
        except TypeError as e:
            logger.error(f"Error serializing enriched data to JSON: {e}")
        except Exception as e:
            logger.error(f"Unexpected error when adding enriched data header: {e}")
    else:
        logger.info("No enrichment data found or fetched.")

    return request